#include <bits/stdc++.h>
using namespace std;
typedef long long ll;
const int N=1e6+6;
int n,d[N],p[N],c[N],q[N];
ll s[N],val[N],f[N];
ll dist(int x,int y){
    return val[y]-val[x-1]-s[x-1]*(d[y]-d[x-1]);
}
ll fac(int x){
    return f[x+1]+c[x]+val[x];
}
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%d%d%d",&d[i],&p[i],&c[i]);
        s[i]=s[i-1]+p[i];
    }
    val[1]=0;
    for(int i=2;i<=n;i++)
        val[i]=val[i-1]+s[i-1]*(d[i]-d[i-1]);
    int hh=0,tt=0;
    q[0]=n;
    for(int i=n;i;i--){
        while(hh<tt && fac(q[hh])-fac(q[hh+1])>=(__int128)s[i-1]*(d[q[hh]]-d[q[hh+1]]))
            hh++;
        int j=q[hh];
        f[i]=dist(i,j)+(s[j-1]-s[i-1]>0)*c[j]+f[j+1];
        while(hh<tt && (__int128)(fac(q[tt])-fac(q[tt-1]))*(d[i-1]-d[q[tt]])<=(__int128)(fac(i-1)-fac(q[tt]))*(d[q[tt]]-d[q[tt-1]]))
            tt--;
        q[++tt]=i-1;
    }
    printf("%lld",f[1]);
    return 0;
}
